radii = range(0.2, 2.25; length=30)
energies = range(0.0, 2.45; length=100)
;#hide

# Use [`make_loss_fn`](@ref) to define a loss function that measures agreement
# between the experimental data and the fitted model.
#
# It is important that we initialized the system to the desired magnetic order
# (here, AFM) prior to calling `make_loss_fn`. Doing so reduces the burden on
# [`minimize_energy!`](@ref). Each time the loss function is executed,
# `minimize_energy!` only needs to refine the canting angle for a cloned system
# with updated parameter values.
#
# The function [`squared_error_fitted`](@ref) automatically fits the overall
# scale of the experimental intensities.
#
# The squared error can become misleading if some model intensity "leaks" beyond
# the energy bounds of the experimental measurement. To combat this, we include
# a regularization term that penalizes any intensity appearing at those energy
# bounds.

formfactors = [1 => FormFactor("Pr4")]
measure = ssf_perp(sys; formfactors)
kernel = gaussian(fwhm=0.05)

loss = make_loss_fn(sys, labels) do sys
    minimize_energy!(sys)
    swt = SpinWaveTheory(sys; measure)

    res = powder_average(cryst, radii, 500) do qs
        intensities(swt, qs; energies, kernel)
    end

    leakage_penalty = 1e-2 * energies[end]^2 * norm(res.data[end, :])^2 / length(radii)

    return squared_error_fitted(ref_data, res.data; scale=true).error + leakage_penalty
end

# The loss can be evaluated at arbitrary parameter values. Lower is better.

loss([0.9, -0.5, 0.9, +0.5])

# Define a mapping from the unconstrained optimization variables ``[J, Γ]`` to
# the full set of model parameters, ``[J, Γ, J', Γ']``. Use this mapping to
# define a loss function that acts in the reduced variable space.

param_mapping((J, Γ)) = [J, Γ, J, -Γ]
loss_reduced(x) = loss(param_mapping(x))

@assert loss_reduced([0.9, -0.5]) == loss([0.9, -0.5, 0.9, +0.5])

# Minimize the loss using the
# [Optim](https://github.com/JuliaNLSolvers/Optim.jl) package.

import Optim

options = Optim.Options(
    iterations = 100,
    g_tol      = 1e-5,
    show_trace = true,
    show_every = 5,
)

guess = [0.9, -0.5]
fit = Optim.optimize(loss_reduced, guess, Optim.NelderMead(), options)

# Report the optimized parameters with uncertainties. Because the model ansatz
# is intentionally simplified, these error bar estimates are likely too small.
# See the documentation of [`uncertainty_matrix`](@ref) for discussion.

@assert isapprox(fit.minimizer, [1.186, -0.302]; rtol=1e-2) #hide
uncertainty = uncertainty_matrix(loss_reduced, fit.minimizer)
error_bars = sqrt.(diag(uncertainty))
println(round.(fit.minimizer; digits=2), " ± ", round.(error_bars; digits=2))

# The optimized parameters are in good agreement with previous work:
#
# | Parameter | This study (meV) | Okuma et al. (meV) |
# |:----------|-----------------:|-------------------:|
# | J         |  1.19            |  1.22              |
# | Γ         | -0.30            | -0.27              |
#
# Finally, plot experimental and simulated intensities as they are seen by the
# loss function. The `scale` factor returned by [`squared_error_fitted`](@ref)
# allows to put both plots on the same [global intensity scale](@ref "Structure
# Factor Conventions").

set_params!(sys, labels, param_mapping(fit.minimizer))

minimize_energy!(sys)
swt = SpinWaveTheory(sys; measure)

res = powder_average(cryst, radii, 1000) do qs
    intensities(swt, qs; energies, kernel)
end

(; scale) = squared_error_fitted(ref_data, res.data; scale=true)

fig = Figure(; size=(600, 800))

res.data[findall(isnan, ref_data)] .= NaN
plot_intensities!(fig[2, 1], res; colormap=:jet1, colorrange=(0, 10.0),
                  title="Optimized model fit", units)

res.data .= ref_data * scale
plot_intensities!(fig[1, 1], res; colormap=:jet1, colorrange=(0, 10.0),
                  title="Experimental data (coarsened)", units)
fig
